class Solution extends SolBase {
    public int rand10() {
        int num;
        do {
            int r1 = rand7();
            int r2 = rand7();
            num = (r1 - 1) * 7 + r2; // 1..49 uniform
        } while (num > 40);         // reject 41..49
        return (num - 1) % 10 + 1;  // 1..10 uniform
    }
}
```
